import{_ as a,o as r,c as t,ag as o}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Player Report Cards","description":"","frontmatter":{},"headers":[],"relativePath":"report-cards/index.md","filePath":"report-cards/index.md"}'),i={name:"report-cards/index.md"};function n(s,e,l,c,d,h){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="player-report-cards" tabindex="-1">Player Report Cards <a class="header-anchor" href="#player-report-cards" aria-label="Permalink to &quot;Player Report Cards&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Player report cards compile a player&#39;s stats, analytics charts, mechanics assessments, and coach comments into a shareable document. They are designed to communicate player development progress to families in a professional format.</p><h2 id="generating-a-report-card" tabindex="-1">Generating a Report Card <a class="header-anchor" href="#generating-a-report-card" aria-label="Permalink to &quot;Generating a Report Card&quot;">​</a></h2><ol><li>Navigate to a player&#39;s profile</li><li>Tap <strong>Generate Report Card</strong></li><li>Select the date range — season to date or a specific period</li><li>Add coach comments (optional but recommended)</li><li>The report card generates automatically</li></ol><h2 id="report-card-contents" tabindex="-1">Report Card Contents <a class="header-anchor" href="#report-card-contents" aria-label="Permalink to &quot;Report Card Contents&quot;">​</a></h2><ul><li><strong>Player header</strong> — name, jersey number, team, season</li><li><strong>Season stats</strong> — key counting stats for all four areas</li><li><strong>Performance charts</strong> — trend charts for key metrics</li><li><strong>Mechanics assessment</strong> — radar charts for all four mechanics areas with top strength and top focus area</li><li><strong>Training plan summary</strong> — active training plans</li><li><strong>Coach comments</strong> — free text from the coach</li></ul><h2 id="sharing-with-families" tabindex="-1">Sharing with Families <a class="header-anchor" href="#sharing-with-families" aria-label="Permalink to &quot;Sharing with Families&quot;">​</a></h2><p>Tap <strong>Share</strong> to generate a shareable link. The link:</p><ul><li>Works for anyone — no Diamond Analytics account required</li><li>Expires after 30 days</li><li>Shows a read-only version of the report card</li><li>Can be shared via text, email, or any messaging app</li></ul><h2 id="pdf-export" tabindex="-1">PDF Export <a class="header-anchor" href="#pdf-export" aria-label="Permalink to &quot;PDF Export&quot;">​</a></h2><p>Tap <strong>Export PDF</strong> to generate a PDF version of the report card suitable for printing or attaching to an email.</p><h2 id="coach-comments-best-practices" tabindex="-1">Coach Comments Best Practices <a class="header-anchor" href="#coach-comments-best-practices" aria-label="Permalink to &quot;Coach Comments Best Practices&quot;">​</a></h2><p>The mechanics assessment section provides specific data to reference in your comments:</p><ul><li>Mention specific strengths by name (&quot;Your hip rotation score of 2.8 shows consistent technique&quot;)</li><li>Reference focus areas with context (&quot;We are working on your arm path — the trend is improving&quot;)</li><li>Connect observations to training plans (&quot;Continue the changeup command drills we started in March&quot;)</li></ul><p>Specific, data-referenced comments are more valuable to families than general feedback.</p>',16)])])}const u=a(i,[["render",n]]);export{m as __pageData,u as default};
